+			name:     "legacy bd.db only",
+			files:    []string{"bd.db"},
+			expectDB: "bd.db",
+		},
+		{
+			name:     "prefers beads.db over other db files",
+			files:    []string{"custom.db", "beads.db", "other.db"},
+			expectDB: "beads.db",
+		},
+		{
+			name:     "skips backup files",
+			files:    []string{"beads.backup.db", "real.db"},
+			expectDB: "real.db",
+		},
+		{
+			name:     "skips vc.db",
